const input = $input.first().json;
const action = input.action || 'search_food';

const UA = 'n8n-claw/1.0 (github.com/freddy-schuetz/n8n-claw)';
const BASE = 'https://world.openfoodfacts.org';
const SEARCH_BASE = 'https://search.openfoodfacts.org';
const FIELDS = 'product_name,brands,quantity,nutriscore_grade,nova_group,ecoscore_grade,nutriments,ingredients_text,allergens_tags,labels_tags,categories_tags_en,serving_size';

function getBrand(p) {
  if (Array.isArray(p.brands)) return p.brands.join(', ');
  return p.brands || '';
}

function formatProduct(p) {
  let out = '';
  const name = p.product_name || 'Unknown';
  const brand = getBrand(p);
  out += name + (brand ? ' (' + brand + ')' : '') + '\n';
  if (p.quantity) out += '  Size: ' + p.quantity + '\n';
  if (p.nutriscore_grade) out += '  Nutri-Score: ' + p.nutriscore_grade.toUpperCase() + '\n';
  if (p.nova_group) out += '  NOVA group: ' + p.nova_group + '/4\n';
  if (p.ecoscore_grade) out += '  Eco-Score: ' + p.ecoscore_grade.toUpperCase() + '\n';
  if (p.nutriments) {
    const n = p.nutriments;
    out += '  Nutrition per 100g:';
    if (n['energy-kcal_100g'] !== undefined) out += ' ' + n['energy-kcal_100g'] + ' kcal,';
    if (n.fat_100g !== undefined) out += ' Fat ' + n.fat_100g + 'g,';
    if (n.carbohydrates_100g !== undefined) out += ' Carbs ' + n.carbohydrates_100g + 'g,';
    if (n.sugars_100g !== undefined) out += ' Sugars ' + n.sugars_100g + 'g,';
    if (n.proteins_100g !== undefined) out += ' Protein ' + n.proteins_100g + 'g,';
    if (n.salt_100g !== undefined) out += ' Salt ' + n.salt_100g + 'g,';
    if (n.fiber_100g !== undefined) out += ' Fiber ' + n.fiber_100g + 'g';
    out = out.replace(/,$/, '') + '\n';
  }
  if (p.allergens_tags && p.allergens_tags.length > 0) {
    out += '  Allergens: ' + p.allergens_tags.map(a => a.replace('en:', '')).join(', ') + '\n';
  }
  if (p.labels_tags && p.labels_tags.length > 0) {
    const labels = p.labels_tags.slice(0, 5).map(l => l.replace('en:', '')).join(', ');
    out += '  Labels: ' + labels + '\n';
  }
  if (p.ingredients_text) {
    const ingr = p.ingredients_text.length > 300 ? p.ingredients_text.substring(0, 300) + '...' : p.ingredients_text;
    out += '  Ingredients: ' + ingr + '\n';
  }
  return out.trim();
}

if (action === 'lookup_barcode') {
  const barcode = (input.barcode || '').trim();
  if (!barcode) {
    return [{ json: { error: 'Parameter "barcode" is required. Provide an EAN-8 or EAN-13 barcode number.' } }];
  }

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: BASE + '/api/v2/product/' + encodeURIComponent(barcode) + '.json?fields=' + FIELDS,
      headers: { 'User-Agent': UA },
      timeout: 15000
    });

    const parsed = typeof data === 'string' ? JSON.parse(data) : data;

    if (!parsed.product || parsed.status === 0) {
      return [{ json: { result: 'Product not found for barcode ' + barcode + '. The product may not be in the OpenFoodFacts database.' } }];
    }

    return [{ json: { result: formatProduct(parsed.product) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to look up barcode: ' + err.message } }];
  }

} else if (action === 'search_food') {
  const query = (input.query || '').trim();
  if (!query) {
    return [{ json: { error: 'Parameter "query" is required. Provide a product name or search term.' } }];
  }

  const limit = Math.min(Math.max(parseInt(input.limit) || 5, 1), 10);

  try {
    const searchFields = 'code,product_name,brands,nutriscore_grade,nova_group,nutriments,allergens_tags,quantity';
    const url = SEARCH_BASE + '/search?q=' + encodeURIComponent(query) + '&page_size=' + limit + '&fields=' + searchFields;

    const data = await helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: { 'User-Agent': UA },
      timeout: 15000
    });

    const parsed = typeof data === 'string' ? JSON.parse(data) : data;
    const products = parsed.hits || parsed.products || [];

    if (products.length === 0) {
      return [{ json: { result: 'No products found for "' + query + '". Try a different search term.' } }];
    }

    const total = parsed.count || products.length;
    let result = 'Found ' + total + ' products for "' + query + '" (showing ' + products.length + '):\n\n';

    for (let i = 0; i < products.length; i++) {
      const p = products[i];
      const name = p.product_name || 'Unknown';
      const brand = getBrand(p);
      result += (i + 1) + '. ' + name + (brand ? ' (' + brand + ')' : '');
      if (p.quantity) result += ' — ' + p.quantity;
      result += '\n';
      if (p.nutriscore_grade) result += '   Nutri-Score: ' + p.nutriscore_grade.toUpperCase();
      if (p.nova_group) result += '  NOVA: ' + p.nova_group + '/4';
      if (p.nutriments && p.nutriments['energy-kcal_100g'] !== undefined) result += '  ' + p.nutriments['energy-kcal_100g'] + ' kcal/100g';
      result += '\n';
      if (p.allergens_tags && p.allergens_tags.length > 0) {
        result += '   Allergens: ' + p.allergens_tags.map(a => a.replace('en:', '')).join(', ') + '\n';
      }
      if (p.code) result += '   Barcode: ' + p.code + '\n';
      result += '\n';
    }

    return [{ json: { result: result.trim() } }];
  } catch (err) {
    if (err.message && err.message.includes('429')) {
      return [{ json: { error: 'Rate limit exceeded. Please try again in a moment.' } }];
    }
    return [{ json: { error: 'Food search failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use lookup_barcode or search_food.' } }];
}
